(window.webpackJsonp=window.webpackJsonp||[]).push([[567],{836:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">points</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> minCostConnectPoints = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">points</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> n=points.length\\n    <span class=\\"hljs-keyword\\">let</span> edges=[]\\n    <span class=\\"hljs-keyword\\">let</span> pq=<span class=\\"hljs-keyword\\">new</span> PriorityQueue(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a[<span class=\\"hljs-number\\">2</span>]-b[<span class=\\"hljs-number\\">2</span>])\\n    <span class=\\"hljs-keyword\\">let</span> uf=<span class=\\"hljs-built_in\\">Array</span>(n).fill().map(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">e,i</span>)=&gt;</span>i)\\n    <span class=\\"hljs-keyword\\">let</span> cost=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;n;i++){\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;n;j++){\\n            <span class=\\"hljs-keyword\\">if</span>(i===j)<span class=\\"hljs-keyword\\">continue</span>\\n            <span class=\\"hljs-keyword\\">let</span> obj=[i,j,dis(i,j)]\\n            edges.push(obj)\\n            pq.insert(obj)\\n        }\\n    }\\n    <span class=\\"hljs-comment\\">// console.log(edges)</span>\\n    <span class=\\"hljs-keyword\\">while</span> (!pq.isEmpty()) {\\n        <span class=\\"hljs-keyword\\">let</span> min = pq.pop()\\n        <span class=\\"hljs-keyword\\">let</span> v = min[<span class=\\"hljs-number\\">0</span>], w = min[<span class=\\"hljs-number\\">1</span>]\\n        <span class=\\"hljs-keyword\\">if</span> (connected(v, w)) <span class=\\"hljs-keyword\\">continue</span>\\n        <span class=\\"hljs-comment\\">// console.log(min)</span>\\n        cost += min[<span class=\\"hljs-number\\">2</span>]\\n        union(v, w)\\n    }\\n\\n    <span class=\\"hljs-keyword\\">return</span> cost\\n    \\n    \\n    \\n    \\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">find</span>(<span class=\\"hljs-params\\">i</span>)</span>{\\n      <span class=\\"hljs-keyword\\">if</span>(i!==uf[i]){\\n        uf[i]=find(uf[i])\\n      }\\n      <span class=\\"hljs-keyword\\">return</span> uf[i]\\n    }\\n\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">union</span>(<span class=\\"hljs-params\\">a,b</span>)</span>{\\n      <span class=\\"hljs-keyword\\">let</span> i=find(a),\\n        j=find(b)\\n      <span class=\\"hljs-keyword\\">if</span>(i===j)<span class=\\"hljs-keyword\\">return</span>\\n      uf[i]=j\\n    }\\n\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">connected</span>(<span class=\\"hljs-params\\">a,b</span>)</span>{\\n      <span class=\\"hljs-keyword\\">let</span> i=find(a),\\n        j=find(b)\\n      <span class=\\"hljs-keyword\\">return</span> i===j\\n    }\\n\\n    \\n    \\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">dis</span>(<span class=\\"hljs-params\\">x,y</span>)</span>{\\n        <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-built_in\\">Math</span>.abs(points[x][<span class=\\"hljs-number\\">0</span>]-points[y][<span class=\\"hljs-number\\">0</span>])+<span class=\\"hljs-built_in\\">Math</span>.abs(points[x][<span class=\\"hljs-number\\">1</span>]-points[y][<span class=\\"hljs-number\\">1</span>])\\n    }\\n    \\n};\\n\\n\\n<span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">PriorityQueue</span>(<span class=\\"hljs-params\\">compareFunction</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span> (!compareFunction) {\\n    compareFunction = <span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a, b</span>) =&gt;</span> a - b\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> heap = [<span class=\\"hljs-literal\\">null</span>]\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">swim</span>(<span class=\\"hljs-params\\">idx</span>) </span>{\\n    <span class=\\"hljs-keyword\\">if</span> (idx &lt; <span class=\\"hljs-number\\">2</span>) <span class=\\"hljs-keyword\\">return</span>\\n    <span class=\\"hljs-keyword\\">let</span> k = <span class=\\"hljs-built_in\\">Math</span>.floor(idx / <span class=\\"hljs-number\\">2</span>)\\n    <span class=\\"hljs-keyword\\">if</span> (compareFunction(heap[idx], heap[k]) &lt; <span class=\\"hljs-number\\">0</span>) {\\n      swap(heap, idx, k)\\n      idx = k\\n      swim(idx)\\n    }\\n  }\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">sink</span>(<span class=\\"hljs-params\\">idx</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> k = <span class=\\"hljs-built_in\\">Math</span>.floor(idx * <span class=\\"hljs-number\\">2</span>)\\n    <span class=\\"hljs-keyword\\">if</span> (k &gt;= heap.length) <span class=\\"hljs-keyword\\">return</span>\\n    <span class=\\"hljs-keyword\\">if</span> (k &lt; heap.length &amp;&amp; heap[k + <span class=\\"hljs-number\\">1</span>] &amp;&amp; compareFunction(heap[k + <span class=\\"hljs-number\\">1</span>], heap[k]) &lt; <span class=\\"hljs-number\\">0</span>) k++\\n    <span class=\\"hljs-keyword\\">if</span> (compareFunction(heap[k], heap[idx]) &lt; <span class=\\"hljs-number\\">0</span>) {\\n      swap(heap, idx, k)\\n      idx = k\\n      sink(idx)\\n    }\\n  }\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">swap</span>(<span class=\\"hljs-params\\">arr, i, j</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> temp = arr[i]\\n    arr[i] = arr[j]\\n    arr[j] = temp\\n  }\\n\\n  <span class=\\"hljs-keyword\\">this</span>.insert = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\">v</span>) </span>{\\n    heap.push(v)\\n    swim(heap.length - <span class=\\"hljs-number\\">1</span>)\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.pop = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\"></span>) </span>{\\n    swap(heap, <span class=\\"hljs-number\\">1</span>, heap.length - <span class=\\"hljs-number\\">1</span>)\\n    <span class=\\"hljs-keyword\\">let</span> v = heap.pop()\\n    sink(<span class=\\"hljs-number\\">1</span>)\\n    <span class=\\"hljs-keyword\\">return</span> v\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.peek = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\"></span>) </span>{\\n    <span class=\\"hljs-keyword\\">return</span> heap[<span class=\\"hljs-number\\">1</span>]\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.size = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\"></span>) </span>{\\n    <span class=\\"hljs-keyword\\">return</span> heap.length - <span class=\\"hljs-number\\">1</span>\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.isEmpty = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\"></span>) </span>{\\n    <span class=\\"hljs-keyword\\">return</span> heap.length === <span class=\\"hljs-number\\">1</span>\\n  }\\n}\\n\\n</code></pre>\\n"],"titleSlug":"min-cost-to-connect-all-points","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a<code>points</code>&nbsp;\u6570\u7ec4\uff0c\u8868\u793a 2D \u5e73\u9762\u4e0a\u7684\u4e00\u4e9b\u70b9\uff0c\u5176\u4e2d&nbsp;<code>points[i] = [x<sub>i</sub>, y<sub>i</sub>]</code>&nbsp;\u3002</p>\\n\\n<p>\u8fde\u63a5\u70b9&nbsp;<code>[x<sub>i</sub>, y<sub>i</sub>]</code> \u548c\u70b9&nbsp;<code>[x<sub>j</sub>, y<sub>j</sub>]</code>&nbsp;\u7684\u8d39\u7528\u4e3a\u5b83\u4eec\u4e4b\u95f4\u7684 <strong>\u66fc\u54c8\u987f\u8ddd\u79bb</strong>&nbsp;\uff1a<code>|x<sub>i</sub> - x<sub>j</sub>| + |y<sub>i</sub> - y<sub>j</sub>|</code>&nbsp;\uff0c\u5176\u4e2d&nbsp;<code>|val|</code>&nbsp;\u8868\u793a&nbsp;<code>val</code>&nbsp;\u7684\u7edd\u5bf9\u503c\u3002</p>\\n\\n<p>\u8bf7\u4f60\u8fd4\u56de\u5c06\u6240\u6709\u70b9\u8fde\u63a5\u7684\u6700\u5c0f\u603b\u8d39\u7528\u3002\u53ea\u6709\u4efb\u610f\u4e24\u70b9\u4e4b\u95f4 <strong>\u6709\u4e14\u4ec5\u6709</strong>&nbsp;\u4e00\u6761\u7b80\u5355\u8def\u5f84\u65f6\uff0c\u624d\u8ba4\u4e3a\u6240\u6709\u70b9\u90fd\u5df2\u8fde\u63a5\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/08/26/d.png\\" style=\\"height:268px; width:214px\\" /></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>points = [[0,0],[2,2],[3,10],[5,2],[7,0]]\\n<strong>\u8f93\u51fa\uff1a</strong>20\\n<strong>\u89e3\u91ca\uff1a\\n</strong><img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/08/26/c.png\\" style=\\"height:268px; width:214px\\" />\\n\u6211\u4eec\u53ef\u4ee5\u6309\u7167\u4e0a\u56fe\u6240\u793a\u8fde\u63a5\u6240\u6709\u70b9\u5f97\u5230\u6700\u5c0f\u603b\u8d39\u7528\uff0c\u603b\u8d39\u7528\u4e3a 20 \u3002\\n\u6ce8\u610f\u5230\u4efb\u610f\u4e24\u4e2a\u70b9\u4e4b\u95f4\u53ea\u6709\u552f\u4e00\u4e00\u6761\u8def\u5f84\u4e92\u76f8\u5230\u8fbe\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>points = [[3,12],[-2,5],[-4,1]]\\n<strong>\u8f93\u51fa\uff1a</strong>18\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>points = [[0,0],[1,1],[1,0],[-1,1]]\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>points = [[-1000000,-1000000],[1000000,1000000]]\\n<strong>\u8f93\u51fa\uff1a</strong>4000000\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>points = [[0,0]]\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= points.length &lt;= 1000</code></li>\\n\\t<li><code>-10<sup>6</sup>&nbsp;&lt;= x<sub>i</sub>, y<sub>i</sub> &lt;= 10<sup>6</sup></code></li>\\n\\t<li>\u6240\u6709\u70b9&nbsp;<code>(x<sub>i</sub>, y<sub>i</sub>)</code>&nbsp;\u4e24\u4e24\u4e0d\u540c\u3002</li>\\n</ul>\\n","title":"1584. \u8fde\u63a5\u6240\u6709\u70b9\u7684\u6700\u5c0f\u8d39\u7528","relatedTags":["\u5e76\u67e5\u96c6"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1584"}')}}]);